/** All known namespaces */
export const Namespaces = Object.keys(Operations)

/** Total operation count across all namespaces */
export const OperationCount = Object.values(Operations).reduce(
  (sum, ns) => sum + Object.keys(ns).length, 0
)

/** Check if an operation exists in a namespace */
export function isValidOperation(namespace: string, op: string): boolean {
  return namespace in Operations && op in Operations[namespace]
}

/** Check if a fully qualified operation exists (e.g., 'crown.state') */
export function isValidOp(op: string): boolean {
  const dot = op.indexOf('.')
  if (dot === -1) return false
  const ns = op.slice(0, dot)
  return ns in Operations && op in Operations[ns]
}

/** Check if a namespace exists */
export function isValidNamespace(ns: string): boolean {
  return ns in Operations
}

/** Get all operation names in a namespace */
export function opsInNamespace(ns: string): string[] {
  return ns in Operations ? Object.keys(Operations[ns]) : []
}

