// ---------------------------------------------------------------------------
// Daemon lookup helpers
// ---------------------------------------------------------------------------

/** Check if a daemon operation exists (SDK/FFI ops OR catalog-composed ops) */
export function isValidDaemonOp(op: string): boolean {
  const dot = op.indexOf('.')
  if (dot === -1) return false
  const ns = op.slice(0, dot)
  return (ns in DaemonOperations && op in DaemonOperations[ns]) ||
         (ns in Operations && op in Operations[ns])
}

/** Get all daemon operation names in a namespace */
export function daemonOpsInNamespace(ns: string): string[] {
  return ns in DaemonOperations ? Object.keys(DaemonOperations[ns]) : []
}

/** Check if a namespace has daemon operations */
export function isValidDaemonNamespace(ns: string): boolean {
  return ns in DaemonOperations
}
